import axios from "axios";
import React, { useEffect, useState } from "react";

const AuthProfile = ({ username }) => {
  const [gitUserData, setGitUserData] = useState({});

  useEffect(() => {
    const getGitUser = async () => {
      const response = await axios.get(
        `https://api.github.com/users/${username}`
      );
      console.log("USER IS HERE", response.data);
      setGitUserData(response.data);
      return response.data;
    };
    getGitUser().catch((e) => console.error(e));
  }, [username]);
  return (
    <div className="user-profile-main-cont">
      <h2 className="mt-10 mb-5 text-2xl font-medium" >YOUR PROFILE</h2>
      <div className="top-cont">
        <img
          src={gitUserData.avatar_url}
          className="user-avatar-img"
          alt="user-img"
        />{" "}
        <div className="name-cont text-left ml-12">
          <span>Username: {gitUserData.login}</span>
          <h2>Fullname: {gitUserData.name}</h2>
          <div>
            {/* <span style={{ display: "block" }}>
              Company:{" "}
              <span style={{ color: "purple", fontWeight: "700" }}>
                {gitUserData.company}
              </span>
            </span> */}
            <span>Public Repos: {gitUserData.public_repos}</span>
          </div>
          <h3>Location: {gitUserData.location}</h3>
          <div className="">
            <span className="">
              Followers: {gitUserData.followers}
             </span>
            <span> Following: {gitUserData.following}</span>
          </div>
          <a
            className="view-ongit-a text-green-600 hover:text-green-500"
            href={gitUserData.html_url}
            target="_blank"
            rel="noreferrer"
          >
            View on GitHub
          </a>
        </div>
      </div>
      <div className="bottom-cont">
        <h3 className="text-xl "><span className="text-2xl ">GitHub Bio:</span> {gitUserData.bio}.</h3>
      </div>
    </div>
  );
};

export default AuthProfile;
